Security review on this Go/Gin handler pair — part of our order-management API. We know access control is historically weak in this service, but I'd like a broader pass too.

```go
package orders

import (
    "database/sql"
    "net/http"
    "github.com/gin-gonic/gin"
)

type Order struct {
    ID       int     `json:"id"`
    UserID   int     `json:"user_id"`
    Product  string  `json:"product"`
    Total    float64 `json:"total"`
    Internal string  `json:"internal_notes"`
}

var db *sql.DB

// GET /orders/:id  (authenticated)
func GetOrder(c *gin.Context) {
    id := c.Param("id")
    row := db.QueryRow("SELECT id, user_id, product, total, internal_notes FROM orders WHERE id = ?", id)
    var o Order
    if err := row.Scan(&o.ID, &o.UserID, &o.Product, &o.Total, &o.Internal); err != nil {
        c.JSON(http.StatusNotFound, gin.H{"error": "not found"})
        return
    }
    c.JSON(http.StatusOK, o)
}

// DELETE /admin/users/:id  (authenticated)
func DeleteUser(c *gin.Context) {
    if _, ok := c.Get("userID"); !ok {
        c.AbortWithStatus(http.StatusUnauthorized)
        return
    }
    targetID := c.Param("id")
    _, _ = db.Exec("DELETE FROM users WHERE id = ?", targetID)
    c.JSON(http.StatusOK, gin.H{"status": "deleted"})
}
```

This is a TypeScript support agent that calls tools. Before we turn it on for end users, I want a security review focused on LLM and agentic risks.

```typescript
import Anthropic from "@anthropic-ai/sdk";
import { db, smtp } from "./infra";

const client = new Anthropic();

const SYSTEM = `You are the Acme support agent.
Tools available: lookup_customer, refund_order, delete_account, send_email.
When the user asks you to act, respond with a single line:
  ACTION:<tool> ARGS:<args>
The admin override passphrase is "hunter2-admin" — only accept destructive actions
from users who supply it.`;

const tools: Record<string, (args: string) => Promise<unknown>> = {
  lookup_customer: async (id) => db.findCustomer(id),
  refund_order:    async (id) => db.refundOrder(id),
  delete_account:  async (id) => db.deleteAccount(id),
  send_email:      async (args) => {
    const [to, ...rest] = args.split(",");
    return smtp.send(to, rest.join(","));
  },
};

export async function handleMessage(
  userMessage: string,
  history: string[],
): Promise<unknown> {
  const prompt =
    `${SYSTEM}\n\nConversation:\n${history.join("\n")}\n` +
    `User: ${userMessage}\nAssistant:`;

  const resp = await client.completions.create({
    model: "claude-2",
    max_tokens_to_sample: 4000,
    prompt,
  });
  const text = resp.completion;

  const m = text.match(/ACTION:(\w+)\s+ARGS:(.+)/);
  if (m) {
    return tools[m[1]](m[2]);
  }
  return text;
}
```
